Чтобы создать окно с двумя кнопками, одна из которых закрывает все sell позиции, а вторая – все buy позиции, вам нужно будет использовать функционал управления позициями в MQL5. Ниже представлен пример скрипта с реализацией:

```mql5
//+------------------------------------------------------------------+
//|                                                   ClosePositions.mq5 |
//|                        Copyright MetaQuotes Software Corp.       |
//|                                        https://www.mql5.com/en/users/mt5sdk |
//+------------------------------------------------------------------+
#property script_show_inputs
#property strict

#include <Controls\Dialog.mqh>

//--- Create a handle for the dialog window
CDialog dialog;
//--- Create handles for the buttons
CButton closeSellButton;
CButton closeBuyButton;

//+------------------------------------------------------------------+
//| Script program start function                                    |
//+------------------------------------------------------------------+
void OnStart()
{
    //--- Create the dialog window
    if (dialog.Create(0, "Close Positions", 0, 0, 250, 60))
    {
        //--- Set the dialog window as a modal window
        dialog.Modal();
        //--- Create Close Sell Button and attach it to the dialog window
        if (closeSellButton.Create(dialog, "Close Sell", 0, 10, 10, 100, 25))
        {
            //--- Set handler for Close Sell Button click event
            closeSellButton.OnClick(OnCloseSellButtonClick);
        }
        //--- Create Close Buy Button and attach it to the dialog window
        if (closeBuyButton.Create(dialog, "Close Buy", 1, 130, 10, 100, 25))
        {
            //--- Set handler for Close Buy Button click event
            closeBuyButton.OnClick(OnCloseBuyButtonClick);
        }
        //--- Show the dialog window
        dialog.Show();
    }
    else
    {
        //--- If the dialog failed to create, print an error message
        Print("Failed to create the dialog window!");
    }
}

//+------------------------------------------------------------------+
//| Handler for Close Sell Button click event                         |
//+------------------------------------------------------------------+
void OnCloseSellButtonClick(void)
{
    //--- Close all sell positions
    CloseAllPositionsOfType(ORDER_TYPE_SELL);
}

//+------------------------------------------------------------------+
//| Handler for Close Buy Button click event                         |
//+------------------------------------------------------------------+
void OnCloseBuyButtonClick(void)
{
    //--- Close all buy positions
    CloseAllPositionsOfType(ORDER_TYPE_BUY);
}

//+------------------------------------------------------------------+
//| Close all positions of the specified type                        |
//+------------------------------------------------------------------+
void CloseAllPositionsOfType(ENUM_ORDER_TYPE orderType)
{
    //--- Request position count
    int totalPositions = PositionsTotal();
    for (int i = totalPositions - 1; i >= 0; i--)
    {
        string symbol = PositionGetSymbol(i);
        if (!PositionSelect(symbol))
            continue;

        //--- Check for position type
        if (PositionGetInteger(POSITION_TYPE) != orderType)
            continue;

        //--- Prepare request structure
        MqlTradeRequest request = {};
        MqlTradeResult result = {};

        request.action = TRADE_ACTION_DEAL;               // Immediate deal
        request.symbol = symbol;                          // Position symbol
        request.volume = PositionGetDouble(POSITION_VOLUME); // Position volume
        request.type = orderType == ORDER_TYPE_BUY ? ORDER_TYPE_SELL : ORDER_TYPE_BUY; // Reverse type for closing
        request.position = PositionGetInteger(POSITION_TICKET); // Position ticket
        request.price = orderType == ORDER_TYPE_BUY ? SymbolInfoDouble(symbol, SYMBOL_BID) : SymbolInfoDouble(symbol, SYMBOL_ASK); // Price to close

        //--- Send trade request
        OrderSend(request, result);

        //--- Check for errors
        if (result.retcode != TRADE_RETCODE_DONE)
        {
            string error_msg = "Failed to close position #";
            error_msg += IntegerToString(request.position) + " Return code: " + IntegerToString(result.retcode);
            Print(error_msg);
        }
    }
}
```

Как вы видите в представленном решении, при нажатии на кнопки вызываются функции-обработчики `OnCloseSellButtonClick` и `OnCloseBuyButtonClick`, которые в свою очередь вызывают функцию `CloseAllPositionsOfType` с параметром `ORDER_TYPE_SELL` или `ORDER_TYPE_BUY`, чтобы закрыть все позиции нужного типа.

Важно отметить, что каждая торговая операция должна быть согласована с вашим торговым алгоритмом и брокерскими условиями. Убедитесь, что у вас есть соответствующие разрешения на торговлю и что вы тестируете такой код в демо-среде, прежде чем запускать на реальном счете.

