  {
   CloseAllSellPositions();
  }

//+------------------------------------------------------------------+
//| Close all sell positions function                                |
//+------------------------------------------------------------------+
void CloseAllSellPositions()
  {
   // Request information about the total number of open positions
   int totalPositions = PositionsTotal();

   // Loop through all open positions in reverse order
   for (int i = totalPositions - 1; i >= 0; i--)
     {
      // Get the ticket of the position
      ulong positionTicket = PositionGetTicket(i);

      // Select the position by its ticket
      if (PositionSelectByTicket(positionTicket))
        {
         // Check if the position is a SELL type
         if (PositionGetInteger(POSITION_TYPE) == POSITION_TYPE_SELL)
           {
            // Prepare the trade request structure
            MqlTradeRequest request = {};
            MqlTradeResult  result = {};

            request.action   = TRADE_ACTION_DEAL; // Type of trade operation
            request.symbol   = PositionGetString(POSITION_SYMBOL); // Symbol of the position
            request.volume   = PositionGetDouble(POSITION_VOLUME); // Volume of the position
            request.type     = ORDER_TYPE_BUY; // We need to send a buy order to close a sell position
            request.position = positionTicket; // Ticket of the position
            request.price    = SymbolInfoDouble(request.symbol, SYMBOL_BID); // Current bid price of the symbol
            request.sl       = 0; // Stop Loss
            request.tp       = 0; // Take Profit
            request.deviation= 5; // Max price deviation in points
            request.magic    = PositionGetInteger(POSITION_MAGIC); // Magic number of the position (if used)
            request.comment  = "Closed by script"; // Comment

            // Send the trade request
            if (!OrderSend(request, result))
              {
               // If the trade request failed, print the error
               Print("Failed to close sell position #", positionTicket, ", Error code: ", GetLastError());
              }
           }
        }
     }
  }
//+------------------------------------------------------------------+
```

